/**
 * Audit ledger for the vanilla DOOM 1.9 trigonometric lookup tables
 * implemented by `finesine`, `finecosine`, `finetangent`, `tantoangle`,
 * and `slopeDiv` in `src/core/trig.ts`.
 *
 * Vanilla DOOM 1.9 uses four canonical fixed-point trig tables. The
 * tables were generated by id Software's offline tool whose source is
 * not publicly available, so they cannot be regenerated bit-for-bit
 * from any IEEE 754 formula — every parity-faithful re-implementation
 * has to ship the exact same byte sequence id Software produced. The
 * tables are:
 *  - `finetangent[FINEANGLES/2]` (4096 entries, fixed_t / int32) —
 *    tangent indexed by fine angle, antisymmetric across its midpoint
 *    (`finetangent[i] === -finetangent[4095 - i]`); the magnitudes
 *    saturate at ±170910304 at the half-circle endpoints.
 *  - `finesine[5*FINEANGLES/4]` (10240 entries, fixed_t / int32) —
 *    sine LUT covering one full circle plus a quarter-circle tail; the
 *    values clip at ±65535 (one ulp below FRACUNIT) near the peaks and
 *    the original generator's IEEE rounding leaves ten ±1 mirror
 *    asymmetries plus twelve ±1 periodicity-extension asymmetries that
 *    every parity-faithful re-implementation must reproduce verbatim.
 *  - `finecosine` (8192-entry pointer alias / Int32Array subarray) —
 *    `&finesine[FINEANGLES/4]`, so `finecosine[i]` is the same memory
 *    cell as `finesine[i + 2048]`. Bit-for-bit aliased, not a copy.
 *  - `tantoangle[SLOPERANGE+1]` (2049 entries, angle_t / uint32) —
 *    arctangent indexed by an 11-bit slope value, monotonic
 *    non-decreasing from `tantoangle[0] = 0` to `tantoangle[2048] =
 *    ANG45 = 0x20000000`.
 *  - `SlopeDiv(unsigned num, unsigned den)` — the helper
 *    `R_PointToAngle` uses to project a Cartesian dy/dx ratio into a
 *    `tantoangle` index. Returns `SLOPERANGE` for `den < 512` (the
 *    divide-by-zero guard) and clamps the quotient to `SLOPERANGE`
 *    when the formula `(num<<3) / (den>>8)` overshoots.
 *
 * This audit pins:
 *  - the canonical C declarations from Chocolate Doom 2.2.1
 *    `tables.h` (table extents, `FINEANGLES`, `SLOPERANGE`,
 *    `ANGLETOFINESHIFT`),
 *  - the canonical C definitions from Chocolate Doom 2.2.1 `tables.c`
 *    (the `finecosine = &finesine[FINEANGLES/4]` pointer alias and the
 *    `SlopeDiv` body),
 *  - the antisymmetric, peak-clipping, mirror-break, and aliasing
 *    invariants every parity-faithful re-implementation has to honour,
 *  - sha256 fingerprints of each runtime table buffer (so a
 *    transcription drift fails loudly instead of silently calibrating
 *    the runtime to a wrong reference),
 *  - a curated probe table of (table, index) → expected hand-pinned
 *    samples at canonical indices (cardinal points, peaks, antisymmetry
 *    pivots, the ten finesine mirror breaks, the tantoangle endpoints,
 *    and several SlopeDiv corner cases),
 *  - and a cross-check helper that any candidate trig-table tuple must
 *    satisfy.
 *
 * Authority order (from `plan_vanilla_parity/SOURCE_CATALOG.md`):
 *   1. local DOS binary `doom/DOOMD.EXE`,
 *   2. local IWAD `doom/DOOM1.WAD`,
 *   3. local Windows oracle `doom/DOOM.EXE` and `doom/chocolate-doom.cfg`,
 *   4. id Software `linuxdoom-1.10` source,
 *   5. Chocolate Doom 2.2.1 source (`tables.h`, `tables.c`, `m_fixed.h`,
 *      `m_fixed.c`, `r_main.c`).
 *
 * The C declarations and definitions below are pinned against authority
 * 5 because they are textual constants that DOSBox cannot disagree
 * with. The probe expectations are the unique values produced by the
 * canonical tables — the focused test re-verifies them against the
 * runtime tables AND against the sha256 fingerprints to defend against
 * transcription drift in this ledger.
 *
 * The audit module deliberately does NOT import from `src/core/trig.ts`.
 * Hardcoding the canonical lengths, hashes, and probe values here means
 * a corruption of `src/core/trig.ts` cannot also silently corrupt the
 * probe table that detects the corruption.
 */

import { createHash } from 'node:crypto';

/** Audited canonical value of FINEANGLES — pinned independently of `src/core/trig.ts`. */
export const AUDITED_FINEANGLES = 8192;

/** Audited canonical value of FINEMASK (= FINEANGLES - 1) — pinned independently. */
export const AUDITED_FINEMASK = 8191;

/** Audited canonical value of ANGLETOFINESHIFT — pinned independently. */
export const AUDITED_ANGLETOFINESHIFT = 19;

/** Audited canonical value of SLOPERANGE — pinned independently. */
export const AUDITED_SLOPERANGE = 2048;

/** Audited canonical value of SLOPEBITS — pinned independently. */
export const AUDITED_SLOPEBITS = 11;

/** Audited canonical value of DBITS (= FRACBITS - SLOPEBITS = 16 - 11) — pinned independently. */
export const AUDITED_DBITS = 5;

/** Audited canonical length of `finetangent` (= FINEANGLES / 2). */
export const AUDITED_FINETANGENT_LENGTH = 4096;

/** Audited canonical length of `finesine` (= 5 * FINEANGLES / 4). */
export const AUDITED_FINESINE_LENGTH = 10_240;

/** Audited canonical offset of `finecosine` into `finesine` (= FINEANGLES / 4). */
export const AUDITED_FINECOSINE_OFFSET = 2048;

/** Audited canonical length of `finecosine` (= FINESINE_LENGTH - FINECOSINE_OFFSET = FINEANGLES). */
export const AUDITED_FINECOSINE_LENGTH = 8192;

/** Audited canonical length of `tantoangle` (= SLOPERANGE + 1). */
export const AUDITED_TANTOANGLE_LENGTH = 2049;

/** Audited canonical sha256 of the `finetangent` Int32Array buffer (4096 little-endian int32s = 16384 bytes). */
export const AUDITED_FINETANGENT_SHA256 = '8988638b066ed2b19a42c6ea1f7d451744e8337845bba4cbb08ac400e521a031';

/** Audited canonical sha256 of the `finesine` Int32Array buffer (10240 little-endian int32s = 40960 bytes). */
export const AUDITED_FINESINE_SHA256 = 'a2a1181edd988c7f3f8220c8ffa82801d7c3bbf7ca9564551e90d877728a2ebb';

/** Audited canonical sha256 of the `finecosine` view (8192 little-endian int32s = 32768 bytes, equal to finesine[2048..10239]). */
export const AUDITED_FINECOSINE_SHA256 = 'ec1f6386e7fb9165608705ff3561f538b7f41c5103d1b6c723dfef07a8f85cbf';

/** Audited canonical sha256 of the `tantoangle` Uint32Array buffer (2049 little-endian uint32s = 8196 bytes). */
export const AUDITED_TANTOANGLE_SHA256 = 'ba4346ce3ac3dcb24c460bcf0ed98d3f8351203ca3bcc1dec1cb822f9dee7e11';

/** Audited canonical magnitude of the largest |finetangent| entry — saturates at ±170910304 at the half-circle endpoints. */
export const AUDITED_FINETANGENT_PEAK_MAGNITUDE = 170_910_304;

/** Audited canonical magnitude of the largest |finesine| entry — clips at FRACUNIT - 1 = 65535 (the table never reaches 1.0 exactly). */
export const AUDITED_FINESINE_PEAK_MAGNITUDE = 65_535;

/** Audited canonical value of `tantoangle[SLOPERANGE]` — equals ANG45 = 0x20000000. */
export const AUDITED_TANTOANGLE_AT_SLOPERANGE = 0x2000_0000;

/**
 * Stable identifier for one pinned fact about the canonical
 * trigonometric lookup tables, the `finecosine` aliasing, or the
 * `SlopeDiv` body.
 */
export type TrigLookupFactId =
  | 'C_HEADER_DEFINE_FINEANGLES'
  | 'C_HEADER_DEFINE_FINEMASK'
  | 'C_HEADER_DEFINE_ANGLETOFINESHIFT'
  | 'C_HEADER_DEFINE_SLOPERANGE'
  | 'C_HEADER_DECLARE_FINETANGENT'
  | 'C_HEADER_DECLARE_FINESINE'
  | 'C_HEADER_DECLARE_FINECOSINE_AS_POINTER'
  | 'C_HEADER_DECLARE_TANTOANGLE'
  | 'C_BODY_FINECOSINE_ALIAS_OFFSET'
  | 'C_BODY_SLOPEDIV';

/**
 * One pinned fact about the canonical trigonometric lookup tables.
 */
export interface TrigLookupFact {
  /** Stable identifier; cross-referenced by the focused test. */
  readonly id: TrigLookupFactId;
  /** Whether the fact comes from the upstream C header, the upstream C body, or the JavaScript decomposition that reproduces it. */
  readonly category: 'c-header' | 'c-body';
  /** Plain-language description of what this fact pins. */
  readonly description: string;
  /** Verbatim C reference snippet. */
  readonly cReference: string;
  /** Reference source path inside the Chocolate Doom 2.2.1 tree. */
  readonly referenceSourceFile: 'src/tables.h' | 'src/tables.c';
}

