/**
 * One curated (table, index) → expected probe.
 *
 * `expected` is the bit-for-bit value of the canonical runtime table
 * cell at `index`, hand-pinned from a one-time inspection of
 * `src/core/trig.ts` and re-checked by the focused test against (a)
 * the runtime cell directly and (b) the audited sha256 fingerprint of
 * the entire table buffer. Drift in either direction fails loudly.
 */
export interface TrigLookupProbe {
  /** Stable identifier; cross-referenced by the focused test. */
  readonly id: TrigLookupProbeId;
  /** Which table this probe inspects, or 'slopeDiv' for the helper function. */
  readonly table: 'finetangent' | 'finesine' | 'finecosine' | 'tantoangle' | 'slopeDiv';
  /** Probe input: an integer index for tables, or a (num, den) pair for slopeDiv. */
  readonly input: number | readonly [number, number];
  /** Expected canonical output. For tables: the value at `input`. For slopeDiv: the return value. */
  readonly expected: number;
  /** Plain-language note explaining what this probe defends against. */
  readonly note: string;
}

